const body = $input.first().json.body;

const subtotal = parseFloat(body.subtotal) || 0;
const iva = +(subtotal * 0.16).toFixed(2);
const amount = +(subtotal + iva).toFixed(2);
const id = body.id || ("PAY-" + Date.now().toString(36).toUpperCase());

const now = new Date().toISOString();
const date = now.slice(0, 10);

const statusHistory = JSON.stringify([
  {
    status: "Autorización",
    timestamp: now,
    changedBy: body.submittedBy || "",
  }
]);

return [{
  json: {
    // Campos para Google Sheets (nombres exactos de columna)
    "ID": id,
    "Fecha de solicitud": date,
    "OC": body.poNumber || "",
    "No. de Proyecto o Departamento para imputar": body.projectNumber || "",
    "Beneficiario": body.beneficiary || "",
    "Concepto de pago": body.concept || "",
    "Subtotal": subtotal,
    "IVA": iva,
    "Monto Solicitado": amount,
    "Divisa": body.currency || "MXN",
    "Departamento solicitante": body.department || "",
    "Persona Solicitante": body.submittedBy || "",
    "Estatus del Pago": "Autorización",
    "StatusHistory": statusHistory,
    // Campos vacíos para que la fila quede completa
    "Listo para pago": "",
    "Pago Programado": "",
    "Autorizado MAC+Operaciones": "",
    "Observaciones de Finanzas": "",
    "Tipo de operación": "",
    "Estatus OC": "",
    "Cliente": "",
    "N° de factura": "",
    "Monto Pagado": "",
    "T/C": "",
    "Monto en MXN": "",
    "Banco": "",
    "Operación": "",
    "Modo pago": "",
    "Prestación del bien o servicio": "",
    "Propuesta": "",
    "Tipo de gasto": "",
    "Link Factura": "",
    "Comprobante de pago": "",
    // Para la respuesta al frontend
    _response: {
      id,
      poNumber: body.poNumber || "",
      projectNumber: body.projectNumber || "",
      beneficiary: body.beneficiary || "",
      concept: body.concept || "",
      subtotal,
      iva,
      amount,
      currency: body.currency || "MXN",
      department: body.department || "",
      status: "Autorización",
      submittedBy: body.submittedBy || "",
      date,
      statusHistory: [{ status: "Autorización", timestamp: now, changedBy: body.submittedBy || "" }],
    }
  }
}];

const rows = $input.all();
const results = [];

for (const row of rows) {
  const d = row.json;
  const id = d["ID"];
  if (!id) continue;

  let statusHistory = [];
  try {
    if (d["StatusHistory"]) {
      statusHistory = JSON.parse(d["StatusHistory"]);
    }
  } catch {}

  results.push({
    json: {
      id,
      poNumber: d["OC"] || "",
      projectNumber: d["No. de Proyecto o Departamento para imputar"] || "",
      beneficiary: d["Beneficiario"] || "",
      concept: d["Concepto de pago"] || "",
      subtotal: parseFloat(d["Subtotal"]) || 0,
      iva: parseFloat(d["IVA"]) || 0,
      amount: parseFloat(d["Monto Solicitado"]) || 0,
      currency: d["Divisa"] || "MXN",
      department: d["Departamento solicitante"] || "",
      status: d["Estatus del Pago"] || "Draft",
      submittedBy: d["Persona Solicitante"] || "",
      date: d["Fecha de solicitud"] || "",
      statusHistory,
      financeObservations: d["Observaciones de Finanzas"] || undefined,
      amountPaid: parseFloat(d["Monto Pagado"]) || undefined,
      exchangeRateUsed: parseFloat(d["T/C"]) || undefined,
      amountMXN: parseFloat(d["Monto en MXN"]) || undefined,
      bankName: d["Banco"] || undefined,
      operationRef: d["Operación"] || undefined,
      paymentMode: d["Modo pago"] || undefined,
      invoiceNumber: d["N° de factura"] || undefined,
      invoiceLink: d["Link Factura"] || undefined,
      expenseType: d["Tipo de gasto"] || undefined,
      operationType: d["Tipo de operación"] || undefined,
      ocStatus: d["Estatus OC"] || undefined,
      client: d["Cliente"] || undefined,
      serviceDelivery: d["Prestación del bien o servicio"] || undefined,
      proposal: d["Propuesta"] || undefined,
      paymentProof: d["Comprobante de pago"] || undefined,
    }
  });
}

return results;

const body = $('Webhook - PATCH Status').first().json.body;
const found = $input.first().json;

if (!found || !found["ID"]) {
  return [{ json: { error: "Solicitud no encontrada", success: false } }];
}

let history = [];
try { if (found["StatusHistory"]) history = JSON.parse(found["StatusHistory"]); } catch {}

const entry = {
  status: body.status,
  timestamp: body.timestamp || new Date().toISOString(),
  changedBy: body.changedBy || "Sistema",
};

// Capture specific comment types
if (body.rejectReason) entry.rejectReason = body.rejectReason;
if (body.clarificationRequest) entry.clarificationRequest = body.clarificationRequest;
if (body.clarificationResponse) entry.clarificationResponse = body.clarificationResponse;
if (body.comment) entry.comment = body.comment;

history.push(entry);

const update = {
  ID: body.id,
  "Estatus del Pago": body.status,
  StatusHistory: JSON.stringify(history),
};

// Handle Finance Observations History separately if sent via status webhook
if (body.financeObservations || (body.comment && !body.rejectReason && !body.clarificationRequest)) {
  const newNoteText = body.financeObservations || body.comment;
  let obsHistory = [];
  try {
    if (found["Observaciones de Finanzas"]) {
      const parsed = JSON.parse(found["Observaciones de Finanzas"]);
      obsHistory = Array.isArray(parsed) ? parsed : [{ text: found["Observaciones de Finanzas"], timestamp: new Date().toISOString(), user: "Legacy" }];
    }
  } catch {
    if (found["Observaciones de Finanzas"]) obsHistory = [{ text: found["Observaciones de Finanzas"], timestamp: new Date().toISOString(), user: "Legacy" }];
  }

  obsHistory.push({
    text: newNoteText,
    timestamp: new Date().toISOString(),
    user: body.changedBy || "Finanzas"
  });
  update["Observaciones de Finanzas"] = JSON.stringify(obsHistory);
}

// Map other specific fields
if (body.rejectReason) update["Motivo de Rechazo"] = body.rejectReason;
if (body.clarificationRequest) update["Solicitud de Aclaración"] = body.clarificationRequest;
if (body.clarificationResponse) update["Respuesta a Aclaración"] = body.clarificationResponse;

return [
  { json: update },
  {
    json: {
      isLog: true,
      "ID Solicitudes": body.id,
      "Evento": body.event || "STATUS_CHANGE",
      "Timestamp": body.timestamp || new Date().toISOString(),
      "Estado resultante": body.status,
      "Usuario": body.changedBy || "",
      "Comentarios": body.rejectReason || body.clarificationRequest || body.clarificationResponse || body.comment || ""
    }
  }
];

// Use the correct trigger name: Webhook - PATCH Status
const body = $('Webhook - PATCH Status').first().json.body;

return [{ 
  json: { 
    success: true, 
    id: body.id, 
    status: body.status 
  } 
}];

const body = $input.first().json.body;
const found = $input.first().json;

const fieldMap = {
  amountPaid: "Monto Pagado",
  exchangeRate: "T/C",
  amountMXN: "Monto en MXN",
  bankName: "Banco",
  operationRef: "Operación",
  paymentMode: "Modo pago",
  invoiceNumber: "N° de factura",
  invoiceLink: "Link Factura",
  expenseType: "Tipo de gasto",
  operationType: "Tipo de operación",
  ocStatus: "Estatus OC",
  client: "Cliente",
  serviceDelivery: "Prestación del bien o servicio",
  proposal: "Propuesta",
  paymentProof: "Comprobante de pago",
};

const update = { "ID": body.id };
for (const [key, col] of Object.entries(fieldMap)) {
  if (body[key] !== undefined && body[key] !== null) update[col] = body[key];
}

// Handle Finance Observations History
let obsHistory = [];
try {
  if (found["Observaciones de Finanzas"]) {
    const parsed = JSON.parse(found["Observaciones de Finanzas"]);
    obsHistory = Array.isArray(parsed) ? parsed : [{ text: found["Observaciones de Finanzas"], timestamp: new Date().toISOString(), user: "Legacy" }];
  }
} catch {
  if (found["Observaciones de Finanzas"]) obsHistory = [{ text: found["Observaciones de Finanzas"], timestamp: new Date().toISOString(), user: "Legacy" }];
}

if (body.financeObservations) {
  obsHistory.push({
    text: body.financeObservations,
    timestamp: new Date().toISOString(),
    user: body.changedBy || "Finanzas"
  });
  update["Observaciones de Finanzas"] = JSON.stringify(obsHistory);
}

// Add status if this update also changes status (e.g. to "Paid")
if (body.status) update["Estatus del Pago"] = body.status;

return [
  { json: update },
  {
    json: {
      isLog: true,
      "ID Solicitudes": body.id,
      "Evento": body.event || "FINANCE_UPDATE",
      "Timestamp": body.timestamp || new Date().toISOString(),
      "Estado resultante": body.status || "N/A",
      "Usuario": body.changedBy || "Finanzas",
      "Comentarios": body.financeObservations || "Actualización de datos financieros"
    }
  }
];

// Get the ID directly from the webhook trigger for 100% reliability
const body = $('Webhook - PATCH Finanzas').first().json.body;

return [{ 
  json: { 
    success: true, 
    id: body.id 
  } 
}];

const rows = $input.all();
const rates = [];

// Helper to convert D/M/YYYY into a sortable number
function getTimestamp(dateStr) {
  const parts = dateStr.includes('/') ? dateStr.split('/') : dateStr.split('-');
  if (parts.length === 3) {
    const d = dateStr.includes('/') 
      ? new Date(parts[2], parts[1] - 1, parts[0]) // D/M/YYYY
      : new Date(parts[0], parts[1] - 1, parts[2]); // YYYY-MM-DD
    return d.getTime();
  }
  return new Date(dateStr).getTime();
}

for (const row of rows) {
  const d = row.json;
  const date = d["Fecha"] || d["fecha"] || "";
  const rawRate = d["Determinación"] || d["Determinacion"] || d["determinación"] || "0";
  const rate = parseFloat(String(rawRate).replace(',', '.'));

  if (date && rate > 0) {
    rates.push({ 
      date, 
      rate, 
      timestamp: getTimestamp(date) 
    });
  }
}

// 1. Sort by real timestamp (Descending)
rates.sort((a, b) => b.timestamp - a.timestamp);

// 2. Take top 30 (most recent)
const last30 = rates.slice(0, 30);

// 3. Reverse back to Ascending for the chart display
last30.reverse();

return last30.map(r => ({ 
  json: { date: r.date, rate: r.rate } 
}));
